import requests
import json
from requests.auth import HTTPBasicAuth

class RabbitMQConfigurator:
    def __init__(self, host, port, username, password):
        self.host = host
        self.port = port
        self.username = username
        self.password = password
        self.base_url = f"http://{self.host}:{self.port}"
        self.auth = HTTPBasicAuth(self.username, self.password)
    
    def create_vhost(self, vhost_name):
        """Create a virtual host"""
        try:
            response = requests.put(
                f"{self.base_url}/api/vhosts/{vhost_name}",
                auth=self.auth,
                headers={'Content-Type': 'application/json'},
                data=json.dumps({"tracing": False})
            )
            response.raise_for_status()
            print(f"Created vhost: {vhost_name}")
            return True
        except requests.exceptions.RequestException as e:
            print(f"Failed to create vhost {vhost_name}: {e}")
            return False
    
    def delete_vhost(self, vhost_name):
        """Delete a virtual host"""
        try:
            response = requests.delete(
                f"{self.base_url}/api/vhosts/{vhost_name}",
                auth=self.auth
            )
            response.raise_for_status()
            print(f"Deleted vhost: {vhost_name}")
            return True
        except requests.exceptions.RequestException as e:
            print(f"Failed to delete vhost {vhost_name}: {e}")
            return False
    
    def create_user(self, username, password, tags=""):
        """Create a user"""
        try:
            response = requests.put(
                f"{self.base_url}/api/users/{username}",
                auth=self.auth,
                headers={'Content-Type': 'application/json'},
                data=json.dumps({
                    "password": password,
                    "tags": tags
                })
            )
            response.raise_for_status()
            print(f"Created user: {username}")
            return True
        except requests.exceptions.RequestException as e:
            print(f"Failed to create user {username}: {e}")
            return False
    
    def delete_user(self, username):
        """Delete a user"""
        try:
            response = requests.delete(
                f"{self.base_url}/api/users/{username}",
                auth=self.auth
            )
            response.raise_for_status()
            print(f"Deleted user: {username}")
            return True
        except requests.exceptions.RequestException as e:
            print(f"Failed to delete user {username}: {e}")
            return False
    
    def set_permissions(self, username, vhost_name, configure, write, read):
        """Set permissions for a user on a vhost"""
        try:
            response = requests.put(
                f"{self.base_url}/api/permissions/{vhost_name}/{username}",
                auth=self.auth,
                headers={'Content-Type': 'application/json'},
                data=json.dumps({
                    "configure": configure,
                    "write": write,
                    "read": read
                })
            )
            response.raise_for_status()
            print(f"Set permissions for user {username} on vhost {vhost_name}")
            return True
        except requests.exceptions.RequestException as e:
            print(f"Failed to set permissions for user {username} on vhost {vhost_name}: {e}")
            return False
    
    def setup_application_environment(self, app_name, user_password, vhost_name=None):
        """Setup complete environment for an application"""
        if vhost_name is None:
            vhost_name = f"/{app_name}"
        
        # Create vhost
        if not self.create_vhost(vhost_name):
            return False
        
        # Create user
        user_name = f"{app_name}_user"
        if not self.create_user(user_name, user_password):
            return False
        
        # Set permissions
        configure = ".*"
        write = ".*"
        read = ".*"
        if not self.set_permissions(user_name, vhost_name, configure, write, read):
            return False
        
        print(f"Successfully configured environment for application: {app_name}")
        return True

